// Auto-generated mock data for Exit-Liquidity Guard (OKX.AI ASP, Theme A "The Seatbelt").
// Anchored to docs/PRD.md — persona is "the calling agent" (position-sizing / DeFAI-copilot
// agents on OKX.AI) and its human operator "who ate a 60% unwind once and never wants their
// bot to do it again."
//
// Edit freely — this file is the demo's reality. The UI never imports this directly; it goes
// through ./data/* so a later swap to real OKX DEX aggregator quotes + eth_call pool reads +
// x402 settlement lookups is a 1-line-per-query change.
//
// EVERY number here is internally consistent:
//  - depth curves are monotonic (slippage rises, realizable is non-decreasing),
//  - pct_of_available_liquidity = size / available_exit_liquidity_usd,
//  - you_are_the_exit_liquidity = pct >= 50 (PRD §6.5),
//  - verdicts follow PRD §6.7 thresholds exactly.

import type {
  Agent,
  CallFeedEvent,
  DepthCurvePoint,
  ExitLiquidityCheck,
  MarketplaceStats,
  Token,
} from './types'

// ---------------------------------------------------------------------------
// Time helpers — all timestamps recent (marketplace opened 2026-06-30, "today" = 2026-07-08).
// ---------------------------------------------------------------------------
export const NOW = new Date('2026-07-08T13:20:00.000Z')
const iso = (d: Date) => d.toISOString()
const minutesAgo = (n: number) => iso(new Date(NOW.getTime() - n * 60_000))
const hoursAgo = (n: number) => iso(new Date(NOW.getTime() - n * 3_600_000))
const daysAgo = (n: number) => iso(new Date(NOW.getTime() - n * 86_400_000))

/**
 * Build a monotonic depth curve from (size, slippage_bps) rungs.
 * realizable = size * (1 - slippage); avg_price = mid * (1 - slippage).
 * Caller is responsible for passing rungs whose realizable is non-decreasing.
 */
function mkCurve(midPrice: number, rungs: Array<[size: number, slippageBps: number]>): DepthCurvePoint[] {
  return rungs.map(([size_usd, slippage_bps]) => {
    const frac = slippage_bps / 10_000
    return {
      size_usd,
      slippage_bps,
      realizable_usd: Math.round(size_usd * (1 - frac)),
      avg_price: Number((midPrice * (1 - frac)).toPrecision(6)),
    }
  })
}

